import { describe, it, expect, vi, describe as viDescribe } from "vitest";
import type { ModelMessage } from "ai";

/**
 * Unit tests for compaction-types.ts
 * Tests all interfaces and types for default values, optional fields, and type compatibility.
 */

// --- Mock Data Helpers ---

const createMockModelMessage = (overrides: Partial<ModelMessage> = {}): ModelMessage => ({
  role: "user",
  content: [{ type: "text", text: "test message" }],
  ...overrides,
});

const createMockDate = (): Date => new Date("2024-01-01T00:00:00Z");

// --- Message Interface Tests ---

describe("Message interface", () => {
  it("should have all required fields", () => {
    const message = {
      createdAt: createMockDate(),
      id: "msg-123",
      modelMessage: createMockModelMessage(),
    };

    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.id).toBe("msg-123");
    expect(message.modelMessage).toBeDefined();
  });

  it("should allow optional originalContent field", () => {
    const messageWithOriginal = {
      createdAt: createMockDate(),
      id: "msg-123",
      modelMessage: createMockModelMessage(),
      originalContent: "original text",
    };

    const messageWithoutOriginal = {
      createdAt: createMockDate(),
      id: "msg-456",
      modelMessage: createMockModelMessage(),
    };

    expect(messageWithOriginal.originalContent).toBe("original text");
    expect(messageWithoutOriginal.originalContent).toBeUndefined();
  });

  it("should be compatible with CheckpointMessage for required fields", () => {
    const message = {
      createdAt: Date.now(),
      id: "msg-123",
      isSummary: false,
      message: createMockModelMessage(),
    };

    // Message should have createdAt as number (Date.now())
    expect(typeof message.createdAt).toBe("number");
  });
});

// --- CheckpointMessage Interface Tests ---

describe("CheckpointMessage interface", () => {
  it("should have all required fields", () => {
    const checkpoint: {
      createdAt: number;
      id: string;
      isSummary: boolean;
      message: ModelMessage;
    } = {
      createdAt: Date.now(),
      id: "check-123",
      isSummary: true,
      message: createMockModelMessage(),
    };

    expect(checkpoint.createdAt).toBeDefined();
    expect(checkpoint.id).toBeDefined();
    expect(checkpoint.isSummary).toBe(true);
    expect(checkpoint.message).toBeDefined();
  });

  it("should have optional originalContent field", () => {
    const withOriginal = {
      createdAt: Date.now(),
      id: "check-123",
      isSummary: true,
      message: createMockModelMessage(),
      originalContent: "preserved content",
    };

    const withoutOriginal = {
      createdAt: Date.now(),
      id: "check-456",
      isSummary: false,
      message: createMockModelMessage(),
    };

    expect(withOriginal.originalContent).toBe("preserved content");
    expect(withoutOriginal.originalContent).toBeUndefined();
  });

  it("createdAt should be number (timestamp)", () => {
    const checkpoint = {
      createdAt: Date.now(),
      id: "check-123",
      isSummary: false,
      message: createMockModelMessage(),
    };

    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.createdAt).toBeGreaterThan(0);
  });
});

// --- SessionMetadata Interface Tests ---

describe("SessionMetadata interface", () => {
  it("should have all required fields and accept null for summaryMessageId", () => {
    const sessionWithSummary: {
      completionTokens: number;
      createdAt: number;
      promptTokens: number;
      sessionId: string;
      summaryMessageId: string | null;
      updatedAt: number;
    } = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 200,
      sessionId: "session-123",
      summaryMessageId: "summary-456",
      updatedAt: Date.now(),
    };

    const sessionWithoutSummary: {
      completionTokens: number;
      createdAt: number;
      promptTokens: number;
      sessionId: string;
      summaryMessageId: string | null;
      updatedAt: number;
    } = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 200,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(sessionWithSummary.summaryMessageId).toBe("summary-456");
    expect(sessionWithoutSummary.summaryMessageId).toBeNull();
  });

  it("should have numeric token fields", () => {
    const session = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 200,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(typeof session.completionTokens).toBe("number");
    expect(typeof session.promptTokens).toBe("number");
    expect(session.completionTokens).toBeGreaterThanOrEqual(0);
    expect(session.promptTokens).toBeGreaterThanOrEqual(0);
  });
});

// --- CompactionConfig Interface Tests ---

describe("CompactionConfig interface", () => {
  it("should have all optional fields undefined by default", () => {
    const emptyConfig = {};

    expect(emptyConfig.contextLimit).toBeUndefined();
    expect(emptyConfig.enabled).toBeUndefined();
    expect(emptyConfig.keepRecentTokens).toBeUndefined();
    expect(emptyConfig.maxTokens).toBeUndefined();
    expect(emptyConfig.reserveTokens).toBeUndefined();
    expect(emptyConfig.speculativeStartRatio).toBeUndefined();
    expect(emptyConfig.summarizeFn).toBeUndefined();
    expect(emptyConfig.thresholdRatio).toBeUndefined();
  });

  it("should accept custom values for all fields", () => {
    const customConfig = {
      contextLimit: 100000,
      enabled: true,
      keepRecentTokens: 3000,
      maxTokens: 10000,
      reserveTokens: 2500,
      speculativeStartRatio: 0.5,
      summarizeFn: async (messages: ModelMessage[]) => "summary",
      thresholdRatio: 0.6,
    };

    expect(customConfig.contextLimit).toBe(100000);
    expect(customConfig.enabled).toBe(true);
    expect(customConfig.keepRecentTokens).toBe(3000);
    expect(customConfig.maxTokens).toBe(10000);
    expect(customConfig.reserveTokens).toBe(2500);
    expect(customConfig.speculativeStartRatio).toBe(0.5);
    expect(customConfig.summarizeFn).toBeDefined();
    expect(typeof customConfig.summarizeFn).toBe("function");
    expect(customConfig.thresholdRatio).toBe(0.6);
  });

  describe("default values", () => {
    it("keepRecentTokens should default to 2000", () => {
      const config = {};
      const defaultValue = config.keepRecentTokens ?? 2000;
      expect(defaultValue).toBe(2000);
    });

    it("maxTokens should default to 8000", () => {
      const config = {};
      const defaultValue = config.maxTokens ?? 8000;
      expect(defaultValue).toBe(8000);
    });

    it("reserveTokens should default to 2000", () => {
      const config = {};
      const defaultValue = config.reserveTokens ?? 2000;
      expect(defaultValue).toBe(2000);
    });

    it("thresholdRatio should default to 0.5", () => {
      const config = {};
      const defaultValue = config.thresholdRatio ?? 0.5;
      expect(defaultValue).toBe(0.5);
    });

    it("enabled should default to false", () => {
      const config = {};
      const defaultValue = config.enabled ?? false;
      expect(defaultValue).toBe(false);
    });
  });

  describe("speculativeStartRatio validation", () => {
    it("should accept values in valid range 0.15 to 0.95", () => {
      const validRatios = [0.15, 0.5, 0.95];
      for (const ratio of validRatios) {
        const config = { speculativeStartRatio: ratio };
        expect(config.speculativeStartRatio).toBe(ratio);
      }
    });
  });

  it("summarizeFn should accept messages and optional previousSummary", async () => {
    const summarizeFn = vi.fn().mockResolvedValue("test summary");
    const messages = [createMockModelMessage()];

    const result = await summarizeFn(messages, "previous summary");

    expect(summarizeFn).toHaveBeenCalledWith(messages, "previous summary");
    expect(result).toBe("test summary");
  });
});

// --- PruningConfig Interface Tests ---

describe("PruningConfig interface", () => {
  it("should have all optional fields undefined by default", () => {
    const emptyConfig = {};

    expect(emptyConfig.enabled).toBeUndefined();
    expect(emptyConfig.minSavingsTokens).toBeUndefined();
    expect(emptyConfig.protectedToolNames).toBeUndefined();
    expect(emptyConfig.protectRecentTokens).toBeUndefined();
    expect(emptyConfig.replacementText).toBeUndefined();
  });

  describe("default values", () => {
    it("enabled should default to false", () => {
      const config = {};
      expect(config.enabled ?? false).toBe(false);
    });

    it("minSavingsTokens should default to 200", () => {
      const config = {};
      expect(config.minSavingsTokens ?? 200).toBe(200);
    });

    it("protectRecentTokens should default to 2000", () => {
      const config = {};
      expect(config.protectRecentTokens ?? 2000).toBe(2000);
    });

    it("replacementText should default to '[output pruned — too large]'", () => {
      const config = {};
      expect(config.replacementText ?? "[output pruned — too large]").toBe(
        "[output pruned — too large]"
      );
    });
  });

  it("should accept array of protected tool names", () => {
    const config = {
      protectedToolNames: ["tool1", "tool2", "tool3"],
    };

    expect(config.protectedToolNames).toHaveLength(3);
    expect(config.protectedToolNames).toContain("tool1");
  });
});

// --- ContinuationVariant Type Tests ---

describe("ContinuationVariant type", () => {
  it("should accept 'manual' literal", () => {
    const variant: "manual" | "auto-with-replay" | "tool-loop" = "manual";
    expect(variant).toBe("manual");
  });

  it("should accept 'auto-with-replay' literal", () => {
    const variant: "manual" | "auto-with-replay" | "tool-loop" = "auto-with-replay";
    expect(variant).toBe("auto-with-replay");
  });

  it("should accept 'tool-loop' literal", () => {
    const variant: "manual" | "auto-with-replay" | "tool-loop" = "tool-loop";
    expect(variant).toBe("tool-loop");
  });

  it("should reject invalid variants", () => {
    expect(() => {
      const variant: "manual" | "auto-with-replay" | "tool-loop" = "invalid" as any;
    }).toThrow();
  });
});

// --- CompactionResult Interface Tests ---

describe("CompactionResult interface", () => {
  it("should require success field", () => {
    const result = { success: true };
    expect(result.success).toBe(true);
  });

  it("should require tokensBefore and tokensAfter fields", () => {
    const result = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
    };

    expect(result.tokensBefore).toBe(1000);
    expect(result.tokensAfter).toBe(500);
  });

  it("should allow optional continuationVariant", () => {
    const withVariant = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      continuationVariant: "auto-with-replay" as const,
    };

    const withoutVariant = {
      success: false,
      tokensBefore: 1000,
      tokensAfter: 1000,
      reason: "not enough tokens",
    };

    expect(withVariant.continuationVariant).toBe("auto-with-replay");
    expect(withoutVariant.continuationVariant).toBeUndefined();
  });

  it("should allow optional reason when success is false", () => {
    const failed = {
      success: false,
      tokensBefore: 1000,
      tokensAfter: 1000,
      reason: "Token limit not reached",
    };

    expect(failed.success).toBe(false);
    expect(failed.reason).toBe("Token limit not reached");
  });

  it("should allow optional summaryMessageId", () => {
    const withId = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      summaryMessageId: "summary-123",
    };

    expect(withId.summaryMessageId).toBe("summary-123");
  });
});

// --- PreparedCompactionV2 Interface Tests ---

describe("PreparedCompactionV2 interface", () => {
  it("should have all required fields", () => {
    const prepared = {
      baseMessageIds: ["msg-1", "msg-2"],
      revision: 1,
      splitIndex: 5,
      summaryText: "Compacted summary",
      tokenDelta: -500,
    };

    expect(prepared.baseMessageIds).toHaveLength(2);
    expect(prepared.revision).toBe(1);
    expect(prepared.splitIndex).toBe(5);
    expect(prepared.summaryText).toBe("Compacted summary");
    expect(prepared.tokenDelta).toBe(-500);
  });

  it("should allow optional replayMessage", () => {
    const withReplay = {
      baseMessageIds: ["msg-1"],
      revision: 1,
      splitIndex: 0,
      summaryText: "Summary",
      tokenDelta: -100,
      replayMessage: {
        createdAt: Date.now(),
        id: "replay-123",
        isSummary: true,
        message: createMockModelMessage(),
      },
    };

    const withoutReplay = {
      baseMessageIds: ["msg-1"],
      revision: 1,
      splitIndex: 0,
      summaryText: "Summary",
      tokenDelta: -100,
    };

    expect(withReplay.replayMessage).toBeDefined();
    expect(withoutReplay.replayMessage).toBeUndefined();
  });
});

// --- ActualTokenUsage Interface Tests ---

describe("ActualTokenUsage interface", () => {
  it("should require all fields", () => {
    const usage = {
      completionTokens: 100,
      promptTokens: 200,
      totalTokens: 300,
      updatedAt: createMockDate(),
    };

    expect(usage.completionTokens).toBe(100);
    expect(usage.promptTokens).toBe(200);
    expect(usage.totalTokens).toBe(300);
    expect(usage.updatedAt).toBeInstanceOf(Date);
  });

  it("totalTokens should equal sum of prompt and completion tokens", () => {
    const usage = {
      completionTokens: 100,
      promptTokens: 200,
      totalTokens: 300,
      updatedAt: createMockDate(),
    };

    expect(usage.totalTokens).toBe(usage.promptTokens + usage.completionTokens);
  });
});

// --- ActualTokenUsageInput Interface Tests ---

describe("ActualTokenUsageInput interface", () => {
  it("should have all optional fields", () => {
    const empty = {};

    expect(empty.completionTokens).toBeUndefined();
    expect(empty.inputTokens).toBeUndefined();
    expect(empty.outputTokens).toBeUndefined();
    expect(empty.promptTokens).toBeUndefined();
    expect(empty.totalTokens).toBeUndefined();
    expect(empty.updatedAt).toBeUndefined();
