describe("ContextUsage interface", () => {
  it("should require all fields", () => {
    const usage = {
      limit: 100000,
      percentage: 50,
      remaining: 50000,
      source: "actual" as const,
      used: 50000,
    };

    expect(usage.limit).toBe(100000);
    expect(usage.percentage).toBe(50);
    expect(usage.remaining).toBe(50000);
    expect(usage.source).toBe("actual");
    expect(usage.used).toBe(50000);
  });

  it("should accept 'estimated' as source", () => {
    const usage = {
      limit: 100000,
      percentage: 30,
      remaining: 70000,
      source: "estimated" as const,
      used: 30000,
    };

    expect(usage.source).toBe("estimated");
  });

  it("percentage should be within 0-100 range", () => {
    const testCases = [
      { percentage: 0, valid: true },
      { percentage: 50, valid: true },
      { percentage: 100, valid: true },
      { percentage: -1, valid: false },
      { percentage: 101, valid: false },
    ];

    for (const tc of testCases) {
      const usage = {
        limit: 100000,
        percentage: tc.percentage,
        remaining: 50000,
        source: "actual" as const,
        used: 50000,
      };

      if (tc.valid) {
        expect(usage.percentage).toBe(tc.percentage);
      } else {
        expect(() => {
          if (tc.percentage < 0 || tc.percentage > 100) {
            throw new Error("Invalid percentage");
          }
        }).toThrow();
      }
    }
  });

  it("remaining should equal limit minus used", () => {
    const usage = {
      limit: 100000,
      percentage: 50,
      remaining: 50000,
      source: "actual" as const,
      used: 50000,
    };

    expect(usage.remaining).toBe(usage.limit - usage.used);
  });
});

